// nitpick_ftp.npk — FTP protocol command builder & reply parser (v0.12.2)
//
// Pure Nitpick implementation — no extern dependencies.
// Import with: use "nitpick_ftp.npk".*;
//
// Builds FTP command strings and parses FTP reply lines.
// Actual socket I/O is handled by aria-socket at the application level.

// ── Session ─────────────────────────────────────────────────────────────────

pub func:ftp_create = int64() {
    int64:h = ahash(256);
    ahset(h, "_last_cmd", "");
    ahset(h, "_reply_code", "");
    ahset(h, "_reply_msg", "");
    ahset(h, "_reply_class", "");
    pass h;
};

// ── Commands ────────────────────────────────────────────────────────────────

pub func:ftp_cmd_user = string(int64:h, string:user) {
    ahset(h, "_last_cmd", "USER");
    string:cmd = string_concat("USER ", user);
    cmd = string_concat(cmd, "\n");
    pass cmd;
};

pub func:ftp_cmd_pass = string(int64:h, string:pw) {
    ahset(h, "_last_cmd", "PASS");
    string:cmd = string_concat("PASS ", pw);
    cmd = string_concat(cmd, "\n");
    pass cmd;
};

pub func:ftp_cmd_cwd = string(int64:h, string:dir) {
    ahset(h, "_last_cmd", "CWD");
