};

pub func:ftp_cmd_pasv = string(int64:h) {
    ahset(h, "_last_cmd", "PASV");
    pass "PASV\n";
};

pub func:ftp_cmd_quit = string(int64:h) {
    ahset(h, "_last_cmd", "QUIT");
