};

// ── Reply parsing ───────────────────────────────────────────────────────────

pub func:ftp_parse_reply = int32(int64:h, string:line_str) {
    int64:slen = string_length(line_str);
    if (slen < 3i64) { pass 1i32; }
    string:code = string_substring(line_str, 0i64, 3i64);
    string:cls = string_substring(line_str, 0i64, 1i64);
    ahset(h, "_reply_code", code);
    ahset(h, "_reply_class", cls);
    if (slen > 4i64) {
        string:msg = string_substring(line_str, 4i64, slen);
        ahset(h, "_reply_msg", msg);
    }
    if (slen <= 4i64) {
        ahset(h, "_reply_msg", "");
    }
    pass 0i32;
};

pub func:ftp_reply_code = string(int64:h) {
    string:v = ahget(h, "_reply_code");
    pass v;
};

pub func:ftp_reply_class = string(int64:h) {
    string:v = ahget(h, "_reply_class");
    pass v;
};

pub func:ftp_reply_msg = string(int64:h) {
    string:v = ahget(h, "_reply_msg");
    pass v;
};

pub func:ftp_last_cmd = string(int64:h) {
    string:v = ahget(h, "_last_cmd");
    pass v;
};

