    func:passive    = string(int64:h) { pass raw ftp_cmd_pasv(h); };
    func:bye        = string(int64:h) { pass raw ftp_cmd_quit(h); };
    func:parse      = int32(int64:h, string:l) { pass raw ftp_parse_reply(h, l); };
    func:code       = string(int64:h) { pass raw ftp_reply_code(h); };
    func:cls        = string(int64:h) { pass raw ftp_reply_class(h); };
    func:msg        = string(int64:h) { pass raw ftp_reply_msg(h); };
